   - 平台特定问题需要了解细节

questions.code_template:
/**
 * 约束：父组件传递给子组件的尺寸限制
 */
interface Constraints {
  minWidth: number;
  maxWidth: number;
  minHeight: number;
  maxHeight: number;
}

/**
 * 尺寸：子组件返回给父组件的最终尺寸
 */
interface Size {
  width: number;
  height: number;
}

/**
 * 布局结果
 */
interface LayoutResult {
  size: Size;
  children: Map<string, { offset: { x: number; y: number }; result: LayoutResult }>;
}

/**
 * 组件类型
 */
type ComponentType = 'column' | 'row' | 'container';

/**
 * 组件定义
 */
interface Component {
  id: string;
  type: ComponentType;
  // Container特有属性
  width?: number;   // 固定宽度，null表示填充
  height?: number;  // 固定高度，null表示填充
  // Row/Column特有属性
  children?: Component[];
}

/**
 * 布局算法
 * @param component 组件
 * @param constraints 约束
 * @returns 布局结果
 */
function layout(component: Component, constraints: Constraints): LayoutResult {
  // 实现你的代码
}

questions.reference_solution:
function layout(component: Component, constraints: Constraints): LayoutResult {
  switch (component.type) {
    case 'container':
      return layoutContainer(component, constraints);
    case 'column':
      return layoutColumn(component, constraints);
    case 'row':
      return layoutRow(component, constraints);
    default:
      throw new Error(`Unknown type: ${component.type}`);
  }
}

function layoutContainer(component: Component, constraints: Constraints): LayoutResult {
  const width = component.width !== undefined
    ? clamp(component.width, constraints.minWidth, constraints.maxWidth)
    : constraints.maxWidth;

  const height = component.height !== undefined
    ? clamp(component.height, constraints.minHeight, constraints.maxHeight)
    : constraints.maxHeight;

  return {
    size: { width, height },
    children: new Map()
  };
}

function layoutColumn(component: Component, constraints: Constraints): LayoutResult {
  const children = component.children || [];
  const childrenResults = new Map();

  let totalHeight = 0;
  let maxWidth = 0;

  // 第一遍：计算每个子组件的尺寸
  for (const child of children) {
    const childConstraints: Constraints = {
      minWidth: constraints.minWidth,
      maxWidth: constraints.maxWidth,
      minHeight: 0,
      maxHeight: constraints.maxHeight - totalHeight
    };

    const result = layout(child, childConstraints);
    childrenResults.set(child.id, {
      offset: { x: 0, y: totalHeight },
      result
    });

    totalHeight += result.size.height;
    maxWidth = Math.max(maxWidth, result.size.width);
  }

  return {
    size: {
      width: clamp(maxWidth, constraints.minWidth, constraints.maxWidth),
      height: clamp(totalHeight, constraints.minHeight, constraints.maxHeight)
    },
    children: childrenResults
  };
}

function layoutRow(component: Component, constraints: Constraints): LayoutResult {
  const children = component.children || [];
  const childrenResults = new Map();

  let totalWidth = 0;
  let maxHeight = 0;

  for (const child of children) {
    const childConstraints: Constraints = {
      minWidth: 0,
      maxWidth: constraints.maxWidth - totalWidth,
      minHeight: constraints.minHeight,
      maxHeight: constraints.maxHeight
    };

    const result = layout(child, childConstraints);
    childrenResults.set(child.id, {
      offset: { x: totalWidth, y: 0 },
      result
    });

    totalWidth += result.size.width;
    maxHeight = Math.max(maxHeight, result.size.height);
  }

  return {
    size: {
      width: clamp(totalWidth, constraints.minWidth, constraints.maxWidth),
      height: clamp(maxHeight, constraints.minHeight, constraints.maxHeight)
    },
    children: childrenResults
  };
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

